// frontend/src/components/auth/Register.js
import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import './Auth.css';

const Register = () => {
    const [formData, setFormData] = useState({
        name: '',
        phone: '',
        password: '',
        confirmPassword: '',
        user_type: 'worker',
        township: 'Soweto',
        id_number: ''
    });
    const [loading, setLoading] = useState(false);
    const [localError, setLocalError] = useState('');
    const { register } = useAuth();
    const navigate = useNavigate();

    const townships = [
        'Soweto', 'Alexandra', 'Khayelitsha', 'Tembisa', 'Katlehong',
        'Umlazi', 'Mdantsane', 'Mamelodi', 'Soshanguve', 'Daveyton'
    ];

    const handleChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };

    const validateForm = () => {
        if (formData.password.length < 6) {
            setLocalError('Password must be at least 6 characters');
            return false;
        }
        if (formData.password !== formData.confirmPassword) {
            setLocalError('Passwords do not match');
            return false;
        }
        if (!formData.phone.match(/^27[0-9]{9}$/)) {
            setLocalError('Phone must be in SA format: 27712345678');
            return false;
        }
        return true;
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!validateForm()) return;

        setLoading(true);
        setLocalError('');

        const result = await register({
            name: formData.name,
            phone: formData.phone,
            password: formData.password,
            user_type: formData.user_type,
            township: formData.township,
            id_number: formData.id_number || null
        });

        if (result.success) {
            navigate('/dashboard');
        } else {
            setLocalError(result.message);
        }

        setLoading(false);
    };

    return (
        <div className="auth-container">
            <div className="auth-card">
                <div className="auth-header">
                    <h2>Join Ekasilody</h2>
                    <p>Create your account</p>
                </div>

                {localError && (
                    <div className="auth-error">{localError}</div>
                )}

                <form onSubmit={handleSubmit} className="auth-form">
                    <div className="form-group">
                        <label>Full Name</label>
                        <input
                            type="text"
                            name="name"
                            value={formData.name}
                            onChange={handleChange}
                            placeholder="John Doe"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label>Phone Number</label>
                        <input
                            type="tel"
                            name="phone"
                            value={formData.phone}
                            onChange={handleChange}
                            placeholder="27712345678"
                            required
                        />
                        <small>SA format: 27712345678</small>
                    </div>

                    <div className="form-group">
                        <label>SA ID Number (Optional)</label>
                        <input
                            type="text"
                            name="id_number"
                            value={formData.id_number}
                            onChange={handleChange}
                            placeholder="000101 5084 089"
                        />
                    </div>

                    <div className="form-group">
                        <label>I am a:</label>
                        <select 
                            name="user_type" 
                            value={formData.user_type}
                            onChange={handleChange}
                        >
                            <option value="worker">👷 Worker - Looking for jobs</option>
                            <option value="client">🏠 Client - Need services</option>
                        </select>
                    </div>

                    <div className="form-group">
                        <label>Township</label>
                        <select 
                            name="township" 
                            value={formData.township}
                            onChange={handleChange}
                        >
                            {townships.map(town => (
                                <option key={town} value={town}>{town}</option>
                            ))}
                        </select>
                    </div>

                    <div className="form-group">
                        <label>Password</label>
                        <input
                            type="password"
                            name="password"
                            value={formData.password}
                            onChange={handleChange}
                            placeholder="••••••••"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label>Confirm Password</label>
                        <input
                            type="password"
                            name="confirmPassword"
                            value={formData.confirmPassword}
                            onChange={handleChange}
                            placeholder="••••••••"
                            required
                        />
                    </div>

                    <button 
                        type="submit" 
                        className="auth-button"
                        disabled={loading}
                    >
                        {loading ? 'Creating Account...' : 'Sign Up'}
                    </button>
                </form>

                <div className="auth-footer">
                    <p>Already have an account? <Link to="/login">Sign In</Link></p>
                </div>
            </div>
        </div>
    );
};

export default Register;
